-- cwf_template_library.sql
-- Increment 62 — COMPLETE OPERATIONAL TEMPLATE LIBRARY (43 templates, directive #30).
-- Idempotent: unique index on key + ON CONFLICT DO NOTHING (never overwrites owner edits).
-- Only allowlisted variables; keys steer the official sender map (#29): tx.offer_/trip_/booking_/pod_/
-- detention_/driver_/load_/tracking_ -> dispatch@; tx.invoice_/payment_/settlement_ -> billing@; rest+mk.* -> hello@.
-- body_text derived from body in SQL; CTA button injected from one constant. Nothing sends without provider key.
-- Applied to: staging (snslhvmkjusozgjelghi) and production (rwscphuhpjoudvljvmdk).

create unique index if not exists comm_templates_key_uidx on app_private.comm_templates(key);

with btn as (select '<p style="margin:18px 0 0"><a href="{{action_url}}" style="background:#2563eb;color:#fff;padding:10px 18px;border-radius:8px;text-decoration:none;font-weight:700">Open in LoadBoot</a></p>'::text as html),
seed(key,name,category,subject,body) as (values
('tx.welcome_new_account','Carrier welcome','transactional','Welcome to LoadBoot, {{first_name}}','<p>Hi {{first_name}},</p><p>Welcome to LoadBoot. Your account for <b>{{company_name}}</b> is set up. Next step: complete your onboarding checklist so we can start matching you with loads.</p>[[BTN]]'),
('tx.welcome_partner','Broker partner welcome','transactional','Welcome to the LoadBoot partner network','<p>Hi {{first_name}},</p><p><b>{{company_name}}</b> is registered as a LoadBoot broker partner. Complete verification to start posting loads.</p>[[BTN]]'),
('tx.application_received','Application received','transactional','We received your application','<p>Hi {{first_name}},</p><p>Thanks — we received the application for <b>{{company_name}}</b>. Our team reviews every application personally; you will hear from us shortly.</p>[[BTN]]'),
('tx.verification_pending','Verification pending','transactional','Your verification is in progress','<p>Hi {{first_name}},</p><p>We are verifying <b>{{company_name}}</b> (authority, insurance and documents). No action needed unless we ask for something specific.</p>[[BTN]]'),
('tx.changes_requested','Changes requested','transactional','Action needed on your application','<p>Hi {{first_name}},</p><p>We need a correction or an updated item on the <b>{{company_name}}</b> application. Open your portal to see exactly what to fix.</p>[[BTN]]'),
('tx.account_approved','Account approved','transactional','You are approved — welcome aboard','<p>Hi {{first_name}},</p><p>Good news: <b>{{company_name}}</b> is approved and active on LoadBoot.</p>[[BTN]]'),
('tx.account_rejected','Account not approved','transactional','About your LoadBoot application','<p>Hi {{first_name}},</p><p>We could not approve the application for <b>{{company_name}}</b> at this time. The specific reason is in your portal, and you can reapply once it is addressed.</p>[[BTN]]'),
('tx.document_missing','Missing document','transactional','We need your {{document_type}}','<p>Hi {{first_name}},</p><p>We are missing your <b>{{document_type}}</b>. Upload it in the portal to keep your account (and your loads) moving.</p>[[BTN]]'),
('tx.document_rejected','Document rejected','transactional','Your {{document_type}} needs a fix','<p>Hi {{first_name}},</p><p>Your <b>{{document_type}}</b> was reviewed and needs a correction — the reviewer left the exact reason in your portal. Re-upload when ready.</p>[[BTN]]'),
('tx.document_approved','Document approved','transactional','{{document_type}} approved ✓','<p>Hi {{first_name}},</p><p>Your <b>{{document_type}}</b> is reviewed and approved. Nothing else needed on this one.</p>[[BTN]]'),
('tx.document_expiring','Document expiring','transactional','{{document_type}} expires {{document_expiry}}','<p>Hi {{first_name}},</p><p>Your <b>{{document_type}}</b> expires on <b>{{document_expiry}}</b>. Upload the renewal early to avoid interruptions to load offers.</p>[[BTN]]'),
('tx.offer_new','Load offer','transactional','Load offer: {{pickup_city}} → {{delivery_city}}','<p>Hi {{first_name}},</p><p>New load offer for <b>{{carrier_name}}</b>: <b>{{pickup_city}} → {{delivery_city}}</b> (ref {{load_reference}}). Rate, RPM and full details are in your portal — accept, decline or counter before it expires.</p>[[BTN]]'),
('tx.offer_counter','Counteroffer update','transactional','Update on your counteroffer — {{load_reference}}','<p>Hi {{first_name}},</p><p>There is a response to the counteroffer on load <b>{{load_reference}}</b>. Review the new number and respond in your portal.</p>[[BTN]]'),
('tx.offer_accepted','Offer accepted','transactional','Booked: {{pickup_city}} → {{delivery_city}}','<p>Hi {{first_name}},</p><p><b>{{carrier_name}}</b> is booked on <b>{{pickup_city}} → {{delivery_city}}</b> (ref {{load_reference}}). Your booking checklist is ready — complete it to dispatch.</p>[[BTN]]'),
('tx.booking_rate_confirmation','Rate confirmation','transactional','Rate confirmation — {{load_reference}}','<p>Hi {{first_name}},</p><p>The rate confirmation for load <b>{{load_reference}}</b> is ready. Review and return the signed copy via your portal.</p>[[BTN]]'),
('tx.booking_confirmed','Booking confirmed','transactional','Booking confirmed — {{load_reference}}','<p>Hi {{first_name}},</p><p>All booking requirements for <b>{{load_reference}}</b> are complete. Pickup: <b>{{pickup_city}}</b>, delivery: <b>{{delivery_city}}</b>.</p>[[BTN]]'),
('tx.driver_assignment','Driver assignment needed','transactional','Assign a driver — {{load_reference}}','<p>Hi {{first_name}},</p><p>Load <b>{{load_reference}}</b> needs a driver and truck assigned before dispatch. Two taps in your portal.</p>[[BTN]]'),
('tx.trip_pickup_reminder','Pickup reminder','transactional','Pickup at {{appointment_time}} — {{pickup_city}}','<p>Hi {{first_name}},</p><p>Reminder: pickup for load <b>{{load_reference}}</b> at <b>{{pickup_city}}</b>, appointment <b>{{appointment_time}}</b>. Tap "At pickup" on arrival — it protects your detention pay.</p>[[BTN]]'),
('tx.trip_delivery_reminder','Delivery reminder','transactional','Delivery at {{appointment_time}} — {{delivery_city}}','<p>Hi {{first_name}},</p><p>Reminder: delivery for load <b>{{load_reference}}</b> at <b>{{delivery_city}}</b>, appointment <b>{{appointment_time}}</b>. Upload the POD right after unloading.</p>[[BTN]]'),
('tx.trip_checkin_reminder','Check-in reminder','transactional','Quick check-in needed — {{load_reference}}','<p>Hi {{first_name}},</p><p>We have not had a location update on load <b>{{load_reference}}</b> for a while. Share GPS or send a manual check-in from the app.</p>[[BTN]]'),
('tx.tracking_stale_warning','Tracking warning','transactional','Tracking unavailable — {{load_reference}}','<p>Hi {{first_name}},</p><p>Tracking on <b>{{load_reference}}</b> has gone stale. Nothing is cancelled — but dispatch and the customer need a status. Please check in.</p>[[BTN]]'),
('tx.detention_warning','Detention warning','transactional','Free time running out — {{load_reference}}','<p>Hi {{first_name}},</p><p>Free time at the facility on <b>{{load_reference}}</b> is nearly used. Keep your arrive/depart stamps accurate — that is your detention evidence.</p>[[BTN]]'),
('tx.detention_opened','Detention opened','transactional','Detention case opened — {{load_reference}}','<p>Hi {{first_name}},</p><p>A detention case was opened on <b>{{load_reference}}</b> from recorded timestamps. A draft accessorial is pending dispatcher review — nothing bills automatically.</p>[[BTN]]'),
('tx.load_lumper_request','Lumper request','transactional','Lumper authorization — {{load_reference}}','<p>Hi {{first_name}},</p><p>A lumper is required on load <b>{{load_reference}}</b>. Authorization has been requested; keep the receipt — it is reimbursed through your settlement.</p>[[BTN]]'),
('tx.trip_layover','Layover recorded','transactional','Layover on {{load_reference}}','<p>Hi {{first_name}},</p><p>A layover was recorded on load <b>{{load_reference}}</b>. The agreed amount goes to review and then to your settlement.</p>[[BTN]]'),
('tx.load_tonu','TONU update','transactional','TONU on {{load_reference}}','<p>Hi {{first_name}},</p><p>Load <b>{{load_reference}}</b> was cancelled after dispatch. A TONU request is in review — you will see the outcome and amount in your portal.</p>[[BTN]]'),
('tx.trip_breakdown','Breakdown logged','transactional','Breakdown support — {{load_reference}}','<p>Hi {{first_name}},</p><p>Your breakdown on <b>{{load_reference}}</b> is logged and dispatch is coordinating next steps. Update us as things change — we handle the broker side.</p>[[BTN]]'),
('tx.trip_accident','Accident logged','transactional','We are on it — {{load_reference}}','<p>Hi {{first_name}},</p><p>The incident on <b>{{load_reference}}</b> is logged. Safety first — when you are able, add photos and details in the portal. Dispatch is handling notifications.</p>[[BTN]]'),
('tx.trip_exception_update','Exception update','transactional','Update on {{load_reference}}','<p>Hi {{first_name}},</p><p>There is an update on the open issue for load <b>{{load_reference}}</b>. The full note from dispatch is in your portal.</p>[[BTN]]'),
('tx.pod_required','POD required','transactional','POD needed — {{load_reference}}','<p>Hi {{first_name}},</p><p>Delivery on <b>{{load_reference}}</b> is marked complete — upload the signed POD now so invoicing (and your money) is not delayed.</p>[[BTN]]'),
('tx.pod_rejected','POD rejected','transactional','POD needs a fix — {{load_reference}}','<p>Hi {{first_name}},</p><p>The POD for <b>{{load_reference}}</b> could not be accepted — the reviewer left the reason in your portal. Re-upload a corrected copy.</p>[[BTN]]'),
('tx.pod_approved','POD approved','transactional','POD approved ✓ — {{load_reference}}','<p>Hi {{first_name}},</p><p>The POD for <b>{{load_reference}}</b> is approved. Invoicing moves ahead — watch your settlement.</p>[[BTN]]'),
('tx.invoice_ready','Invoice ready','transactional','Invoice {{invoice_number}} is ready','<p>Hi {{first_name}},</p><p>Invoice <b>{{invoice_number}}</b> is ready in your portal, with every line itemized. Payment instructions are on the invoice.</p>[[BTN]]'),
('tx.payment_update','Payment update','transactional','Payment update — {{invoice_number}}','<p>Hi {{first_name}},</p><p>There is a payment status update on invoice <b>{{invoice_number}}</b>. Details are in your portal.</p>[[BTN]]'),
('tx.settlement_ready','Settlement ready','transactional','Settlement {{settlement_number}} is ready','<p>Hi {{first_name}},</p><p>Settlement <b>{{settlement_number}}</b> for <b>{{carrier_name}}</b> is ready to review — gross, fees, accessorials and deductions all itemized.</p>[[BTN]]'),
('tx.invoice_dispute_update','Dispute update','transactional','Dispute update — {{invoice_number}}','<p>Hi {{first_name}},</p><p>Your dispute on <b>{{invoice_number}}</b> has an update from our finance team. The full response is in your portal.</p>[[BTN]]'),
('tx.support_reply','Support reply','transactional','Re: your support request {{support_reference}}','<p>Hi {{first_name}},</p><p>Our team replied to your request <b>{{support_reference}}</b>. Read and respond in your portal — the whole thread stays in one place.</p>[[BTN]]'),
('tx.security_alert','Security alert','transactional','Security notice for your account','<p>Hi {{first_name}},</p><p>We noticed a security-relevant event on the <b>{{company_name}}</b> account. If this was you, no action is needed; otherwise review your sessions now.</p>[[BTN]]'),
('tx.maintenance_notice','Maintenance notice','transactional','Scheduled maintenance','<p>Hi {{first_name}},</p><p>LoadBoot has scheduled maintenance coming up. Active trips and dispatch continue — some portal features may briefly pause. Details inside.</p>[[BTN]]'),
('mk.newsletter','Newsletter','marketing','This month at LoadBoot','<p>Hi {{first_name}},</p><p>Rate trends, new platform features and dispatch tips for <b>{{company_name}}</b> — the short version, once a month.</p>[[BTN]]'),
('mk.promotion','Promotion','marketing','A better deal on your dispatch','<p>Hi {{first_name}},</p><p>A limited offer for carriers like <b>{{carrier_name}}</b> — details and honest terms inside. No gimmicks.</p>[[BTN]]'),
('mk.referral_invite','Referral invite','marketing','Know a carrier who deserves better dispatch?','<p>Hi {{first_name}},</p><p>Refer a carrier to LoadBoot — when they start rolling, we say thank you. Simple, fair, unlimited referrals.</p>[[BTN]]'),
('mk.reengagement','Re-engagement','marketing','We kept your seat, {{first_name}}','<p>Hi {{first_name}},</p><p>It has been a while since <b>{{company_name}}</b> booked with us. The board is busier than ever — here is what changed since you left.</p>[[BTN]]')
)
insert into app_private.comm_templates(key,name,category,channels,channel,subject,body,body_text,variables,status,active)
select s.key, s.name, s.category, '{email,portal}'::text[], 'email', s.subject,
  replace(s.body,'[[BTN]]',b.html),
  regexp_replace(replace(replace(replace(s.body,'[[BTN]]', 'Open in LoadBoot: {{action_url}}'),'<p>',''),'</p>', chr(10)), '<[^>]+>', '', 'g'),
  array(select distinct m[1] from regexp_matches(s.subject||' '||s.body, '\{\{\s*([a-z_]+)\s*\}\}', 'g') m) || array['action_url'],
  'published', true
from seed s cross join btn b
on conflict (key) do nothing;
